#[derive(Debug, Deserialize)]
struct FixtureFile {
    #[allow(dead_code, reason = "metadata kept for diagnostics")]
    metadata: serde_json::Value,
    fixtures: Vec<Fixture>,
}

#[derive(Debug, Deserialize, Clone)]
struct Fixture {
    case: String,
    #[allow(dead_code, reason = "kept for diagnostics")]
    module: String,
    #[allow(dead_code, reason = "kept for diagnostics")]
    op: String,
    #[allow(dead_code, reason = "kept for diagnostics")]
    description: String,
    #[serde(default)]
    cascade_skip: Option<String>,
    // Numeric inputs — shapes are alongside values.
    #[serde(default)]
    input: Option<Vec<f64>>,
    #[serde(default)]
    input_shape: Option<Vec<usize>>,
    #[serde(default)]
    input_a: Option<Vec<f64>>,
    #[serde(default)]
    input_b: Option<Vec<f64>>,
    #[serde(default)]
    shape_a: Option<Vec<usize>>,
    #[serde(default)]
    shape_b: Option<Vec<usize>>,
    #[serde(default)]
    constant: Option<Vec<f64>>,
    #[serde(default)]
    grad_out: Option<Vec<f64>>,
    // Expected outputs.
    #[serde(default)]
    expected_output: Option<Vec<f64>>,
    #[serde(default)]
    expected_output_0: Option<Vec<f64>>,
    #[serde(default)]
    expected_output_1: Option<Vec<f64>>,
    #[serde(default)]
    expected_grad_a: Option<Vec<f64>>,
    #[serde(default)]
    expected_grad_b: Option<Vec<f64>>,
    #[serde(default)]
    expected_shape: Option<Vec<usize>>,
    // Tolerance — per fixture.
    #[serde(default)]
    tol: Option<f64>,
    // Catch-all for fields we don't need to parse structurally.
    #[serde(flatten)]
    _rest: serde_json::Value,
}

/// Tolerance for interpreter numeric tests (f32 arithmetic on CPU).
const DEFAULT_TOL: f32 = 1e-5;

/// Sentinel value in `cascade_skip` for spec-only fixtures.
const SPEC_ONLY_SKIP: &str = "spec-only marker, no PyTorch reference";

fn load_fixtures() -> FixtureFile {
    let p = PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("tests")
        .join("conformance")
        .join("fixtures.json");
    let bytes = std::fs::read(&p).unwrap_or_else(|e| {
        panic!(
            "read {} failed: {e}. Run \
             `python3 scripts/regenerate_jit_interpreter_fixtures.py` first.",
            p.display()
        )
    });
    serde_json::from_slice(&bytes).unwrap_or_else(|e| panic!("parse {}: {e}", p.display()))
}

fn find_fixture<'a>(fixtures: &'a [Fixture], case: &str) -> &'a Fixture {
    fixtures
        .iter()
        .find(|f| f.case == case)
        .unwrap_or_else(|| panic!("fixture not found: {case}"))
}

// ---------------------------------------------------------------------------
// Tensor construction helpers
// ---------------------------------------------------------------------------

/// Build a 1-D f32 tensor (no grad).
fn vec_f32(data: &[f64]) -> Tensor<f32> {
    let data_f32: Vec<f32> = data.iter().map(|&v| v as f32).collect();
    let n = data_f32.len();
    ferrotorch_core::from_vec(data_f32, &[n]).unwrap()
}

/// Build an n-D f32 tensor from a flat buffer and explicit shape (no grad).
fn shaped_f32(data: &[f64], shape: &[usize]) -> Tensor<f32> {
    let data_f32: Vec<f32> = data.iter().map(|&v| v as f32).collect();
    ferrotorch_core::from_vec(data_f32, shape).unwrap()
}

/// Build a 1-D f32 tensor with `requires_grad = true`.
fn grad_vec(data: &[f64]) -> Tensor<f32> {
    let data_f32: Vec<f32> = data.iter().map(|&v| v as f32).collect();
    let n = data_f32.len();
    Tensor::from_storage(TensorStorage::cpu(data_f32), vec![n], true)
        .unwrap()
        .requires_grad_(true)
}

// ---------------------------------------------------------------------------
// Assertion helpers
// ---------------------------------------------------------------------------

fn assert_close(actual: &[f32], expected: &[f64], tol: f32, label: &str) {
    assert_eq!(
        actual.len(),
        expected.len(),
        "{label}: length mismatch: actual {} vs expected {}",
        actual.len(),
        expected.len()
    );
    for (i, (&a, &e)) in actual.iter().zip(expected.iter()).enumerate() {
        let e_f32 = e as f32;
        assert!(
            (a - e_f32).abs() < tol,
            "{label}[{i}]: got {a}, expected {e_f32} (diff {:.2e}, tol {tol:.2e})",
            (a - e_f32).abs()
        );
    }
}

fn tol_f32(f: &Fixture) -> f32 {
    f.tol.map(|v| v as f32).unwrap_or(DEFAULT_TOL)
}

