/// Returns `Some(reason)` if the given test case should be skipped due to a
/// known cascade bug, or `None` if the test is live.
///
/// Keep this function sorted by issue number for easy auditing.
fn cascade_skip(_case: &str) -> Option<&'static str> {
    // No cascade bugs have been filed for C7.2 yet. Entries will be added
    // here as failures are discovered and cross-linked via:
    //   `crosslink quick "<title>" -p high -l rust,jit,bug,conformance`
    None
}

