/// Fixture-driven: interpret a graph built equivalent to PyTorch x + x.
#[test]
fn interpreter_add_self_matches_reference() {
    let all = load_fixtures();
    let f = find_fixture(&all.fixtures, "interp_add_self");
    if let Some(reason) = &f.cascade_skip {
        if reason == SPEC_ONLY_SKIP {
            return;
        }
        eprintln!("cascade_skip(interp_add_self): {reason}");
        return;
    }
    if let Some(reason) = cascade_skip("interp_add_self") {
        eprintln!("cascade_skip(interp_add_self): {reason}");
        return;
    }

    let input_data = f.input.as_ref().expect("input field");
    let input_shape = f.input_shape.as_ref().expect("input_shape field");
    let expected = f.expected_output.as_ref().expect("expected_output field");
    let tol = tol_f32(f);

    // Build IrGraph: y = x + x
    let mut g = IrGraph::new();
    let x = g.add_input(input_shape.clone());
    let (_, add_outs) = g.add_node(IrOpKind::Add, vec![x, x], vec![input_shape.clone()]);
    g.set_outputs(vec![add_outs[0]]);

    let tensor = shaped_f32(input_data, input_shape);
    let result = interpret::<f32>(&g, &[tensor]).unwrap();

    assert_close(result.data().unwrap(), expected, tol, "interp_add_self");
}

/// Fixture-driven: interpret mm(A, B) — IrOpKind::Mm dispatch.
#[test]
fn interpreter_matmul_matches_reference() {
    let all = load_fixtures();
    let f = find_fixture(&all.fixtures, "interp_matmul_2x3_3x2");
    if let Some(reason) = &f.cascade_skip {
        if reason == SPEC_ONLY_SKIP {
            return;
        }
        eprintln!("cascade_skip(interp_matmul): {reason}");
        return;
    }
    if let Some(reason) = cascade_skip("interp_matmul_2x3_3x2") {
        eprintln!("cascade_skip: {reason}");
        return;
    }

    let a_data = f.input_a.as_ref().expect("input_a");
    let b_data = f.input_b.as_ref().expect("input_b");
    let shape_a = f.shape_a.as_ref().expect("shape_a");
    let shape_b = f.shape_b.as_ref().expect("shape_b");
    let expected = f.expected_output.as_ref().expect("expected_output");
    let tol = tol_f32(f);

    let out_shape = vec![shape_a[0], shape_b[1]];

    let mut g = IrGraph::new();
    let a_id = g.add_input(shape_a.clone());
    let b_id = g.add_input(shape_b.clone());
    let (_, mm_outs) = g.add_node(IrOpKind::Mm, vec![a_id, b_id], vec![out_shape.clone()]);
    g.set_outputs(vec![mm_outs[0]]);

    let a_tensor = shaped_f32(a_data, shape_a);
    let b_tensor = shaped_f32(b_data, shape_b);
    let result = interpret::<f32>(&g, &[a_tensor, b_tensor]).unwrap();

    assert_close(
        result.data().unwrap(),
        expected,
        tol,
        "interp_matmul_2x3_3x2",
    );
}

