/// Fixture-driven: interpret_multi with two outputs [x+x, x*x].
#[test]
fn interpreter_multi_output_matches_reference() {
    let all = load_fixtures();
    let f = find_fixture(&all.fixtures, "interp_multi_output");
    if let Some(reason) = &f.cascade_skip {
        if reason == SPEC_ONLY_SKIP {
            return;
        }
        eprintln!("cascade_skip(interp_multi): {reason}");
        return;
    }
    if let Some(reason) = cascade_skip("interp_multi_output") {
        eprintln!("cascade_skip: {reason}");
        return;
    }

    let input_data = f.input.as_ref().expect("input");
    let input_shape = f.input_shape.as_ref().expect("input_shape");
    let expected_0 = f.expected_output_0.as_ref().expect("expected_output_0");
    let expected_1 = f.expected_output_1.as_ref().expect("expected_output_1");
    let tol = tol_f32(f);

    let mut g = IrGraph::new();
    let x = g.add_input(input_shape.clone());
    let (_, add_outs) = g.add_node(IrOpKind::Add, vec![x, x], vec![input_shape.clone()]);
    let (_, mul_outs) = g.add_node(IrOpKind::Mul, vec![x, x], vec![input_shape.clone()]);
    g.set_outputs(vec![add_outs[0], mul_outs[0]]);

    let tensor = shaped_f32(input_data, input_shape);
    let results = interpret_multi::<f32>(&g, &[tensor]).unwrap();

    assert_eq!(results.len(), 2, "interp_multi_output: expected 2 outputs");
    assert_close(
        results[0].data().unwrap(),
        expected_0,
        tol,
        "interp_multi_output[0]",
    );
    assert_close(
        results[1].data().unwrap(),
        expected_1,
        tol,
        "interp_multi_output[1]",
    );
}

