/// Fixture-driven: Sum reduction — scalar output.
#[test]
fn interpreter_reduction_sum_matches_reference() {
    let all = load_fixtures();
    let f = find_fixture(&all.fixtures, "interp_reduction_sum");
    if let Some(reason) = &f.cascade_skip {
        if reason == SPEC_ONLY_SKIP {
            return;
        }
        eprintln!("cascade_skip(interp_sum): {reason}");
        return;
    }
    if let Some(reason) = cascade_skip("interp_reduction_sum") {
        eprintln!("cascade_skip: {reason}");
        return;
    }

    let input_data = f.input.as_ref().expect("input");
    let input_shape = f.input_shape.as_ref().expect("input_shape");
    let expected = f.expected_output.as_ref().expect("expected_output");
    let tol = tol_f32(f);

    let mut g = IrGraph::new();
    let x = g.add_input(input_shape.clone());
    // Sum produces a scalar shape []; but for result comparison we treat it
    // as a 1-element output.
    let (_, sum_outs) = g.add_node(IrOpKind::Sum, vec![x], vec![vec![]]);
    g.set_outputs(vec![sum_outs[0]]);

    let tensor = shaped_f32(input_data, input_shape);
    let result = interpret::<f32>(&g, &[tensor]).unwrap();

    // Sum result is a 1-element tensor (scalar).
    assert_eq!(
        result.numel(),
        1,
        "interp_reduction_sum: expected scalar output"
    );
    let actual_val = result.data().unwrap()[0];
    let expected_val = expected[0] as f32;
    assert!(
        (actual_val - expected_val).abs() < tol,
        "interp_reduction_sum: got {actual_val}, expected {expected_val} (tol {tol:.2e})"
    );
}

// Additional interpreter unit tests (not fixture-driven) covering
// error paths documented in `interpreter.rs`.

/// interpret on a multi-output graph should return an error pointing at
/// interpret_multi.
#[test]
fn interpreter_single_output_errors_on_multi_output_graph() {
    let mut g = IrGraph::new();
    let x = g.add_input(vec![3]);
    let (_, add_outs) = g.add_node(IrOpKind::Add, vec![x, x], vec![vec![3]]);
    let (_, mul_outs) = g.add_node(IrOpKind::Mul, vec![x, x], vec![vec![3]]);
    g.set_outputs(vec![add_outs[0], mul_outs[0]]);

    let t = vec_f32(&[1.0, 2.0, 3.0]);
    let err = interpret::<f32>(&g, &[t]);
    assert!(err.is_err());
    let msg = format!("{}", err.unwrap_err());
    assert!(
        msg.contains("interpret_multi"),
        "expected hint at interpret_multi in: {msg}"
    );
}

/// interpret on a no-output graph should error gracefully.
#[test]
fn interpreter_no_outputs_returns_error() {
    let mut g = IrGraph::new();
    let _x = g.add_input(vec![3]);
    // No set_outputs call.
    let t = vec_f32(&[1.0, 2.0, 3.0]);
    let err = interpret::<f32>(&g, &[t]);
    assert!(err.is_err());
    let msg = format!("{}", err.unwrap_err());
    assert!(
        msg.contains("no outputs"),
        "expected 'no outputs' in: {msg}"
    );
}

/// Input count mismatch should produce a descriptive error.
#[test]
fn interpreter_input_count_mismatch_errors() {
    let mut g = IrGraph::new();
    let a = g.add_input(vec![3]);
    let b = g.add_input(vec![3]);
    let (_, add_outs) = g.add_node(IrOpKind::Add, vec![a, b], vec![vec![3]]);
    g.set_outputs(vec![add_outs[0]]);

    let t = vec_f32(&[1.0, 2.0, 3.0]);
    let err = interpret::<f32>(&g, &[t]); // provide 1 instead of 2
    assert!(err.is_err());
    let msg = format!("{}", err.unwrap_err());
    assert!(
        msg.contains("expected 2 inputs, got 1"),
        "unexpected error message: {msg}"
    );
}

