/// Fixture-driven: TracedModule to_bytes → from_bytes roundtrip.
#[test]
fn module_save_load_bytes_roundtrip() {
    let all = load_fixtures();
    let f = find_fixture(&all.fixtures, "module_save_load_bytes");
    if let Some(reason) = &f.cascade_skip {
        if reason == SPEC_ONLY_SKIP {
            return;
        }
        eprintln!("cascade_skip(module_save_load): {reason}");
        return;
    }
    if let Some(reason) = cascade_skip("module_save_load_bytes") {
        eprintln!("cascade_skip: {reason}");
        return;
    }

    let a_data = f.input_a.as_ref().expect("input_a");
    let b_data = f.input_b.as_ref().expect("input_b");
    let expected = f.expected_output.as_ref().expect("expected_output");
    let tol = tol_f32(f);

    use ferrotorch_core::grad_fns::arithmetic::mul;
    use ferrotorch_core::grad_fns::reduction::sum;

    let a_trace = grad_vec(a_data);
    let b_trace = grad_vec(b_data);

    let module = compile(
        |inputs: &[Tensor<f32>]| -> FerrotorchResult<Tensor<f32>> {
            let product = mul(&inputs[0], &inputs[1])?;
            sum(&product)
        },
        &[a_trace, b_trace],
        None,
    )
    .unwrap();

    // Serialize → deserialize.
    let bytes = module.to_bytes();
    assert!(!bytes.is_empty(), "to_bytes produced empty buffer");

    let restored = TracedModule::<f32>::from_bytes(&bytes).unwrap();
    assert_eq!(restored.input_count(), module.input_count());

    let a_in = shaped_f32(a_data, f.shape_a.as_ref().unwrap_or(&vec![a_data.len()]));
    let b_in = shaped_f32(b_data, f.shape_b.as_ref().unwrap_or(&vec![b_data.len()]));
    let result = restored.forward_multi(&[a_in, b_in]).unwrap();

    assert_eq!(
        result.numel(),
        1,
        "module_save_load_bytes: expected scalar output"
    );
    let actual_val = result.data().unwrap()[0];
    let expected_val = expected[0] as f32;
    assert!(
        (actual_val - expected_val).abs() < tol,
        "module_save_load_bytes: got {actual_val}, expected {expected_val} (tol {tol:.2e})"
    );
}

/// Unit: Module trait — forward on a multi-input graph errors with a
/// descriptive message.
#[test]
fn module_forward_on_multi_input_graph_errors() {
    let mut g = IrGraph::new();
    let a = g.add_input(vec![3]);
    let b = g.add_input(vec![3]);
    let (_, add_outs) = g.add_node(IrOpKind::Add, vec![a, b], vec![vec![3]]);
    g.set_outputs(vec![add_outs[0]]);

    let module = TracedModule::<f32>::new(g);
    let t = vec_f32(&[1.0, 2.0, 3.0]);
    let err = module.forward(&t);
    assert!(err.is_err());
    let msg = format!("{}", err.unwrap_err());
    assert!(
        msg.contains("forward_multi"),
        "expected hint at forward_multi in: {msg}"
    );
}

/// Unit: compile_with_config + CompileConfig default values.
#[test]
fn module_compile_with_config_default() {
    let config = CompileConfig::default();
    assert!(config.optimization.constant_folding);
    assert!(config.optimization.dead_code_elimination);
    assert!(config.optimization.operator_fusion);
    assert!(!config.fullgraph);
    assert_eq!(config.cache_size, 8);

    use ferrotorch_core::grad_fns::reduction::sum;

    let x = grad_vec(&[2.0, 3.0]);
    let module = compile_with_config(
        |inputs: &[Tensor<f32>]| -> FerrotorchResult<Tensor<f32>> { sum(&inputs[0]) },
        &[x],
        config,
    )
    .unwrap();

    let result = module.forward(&vec_f32(&[2.0, 3.0])).unwrap();
    let val = result.data().unwrap()[0];
    assert!(
        (val - 5.0_f32).abs() < 1e-5_f32,
        "compile_with_config: got {val}, expected 5.0"
    );
}

/// Unit: CompileConfig::from_optimization.
#[test]
fn module_compile_config_from_optimization() {
    let opt = OptimizationConfig {
        constant_folding: false,
        dead_code_elimination: true,
        operator_fusion: false,
        memory_planning: false,
    };
    let config = CompileConfig::from_optimization(opt);
    assert!(!config.optimization.constant_folding);
    assert!(config.optimization.dead_code_elimination);
    assert!(!config.optimization.operator_fusion);
    assert!(!config.fullgraph); // default
    assert_eq!(config.cache_size, 8); // default
}

