fn module_traced_module_accessors() {
    let mut g = IrGraph::new();
    let x = g.add_input(vec![3]);
    let (_, relu_outs) = g.add_node(IrOpKind::Relu, vec![x], vec![vec![3]]);
    g.set_outputs(vec![relu_outs[0]]);

    let module = TracedModule::<f32>::new(g);
    assert_eq!(module.input_count(), 1);
    assert_eq!(module.output_shape(), &[3]);
    // graph() returns the underlying IrGraph.
    assert!(module.graph().node_count() >= 1);
    // Module trait: parameters are empty; always eval mode.
    assert!(module.parameters().is_empty());
    assert!(!module.is_training());
}

