/// Fixture-driven: Add backward — grad_a and grad_b both equal grad_out.
#[test]
fn aot_add_backward_matches_reference() {
    let all = load_fixtures();
    let f = find_fixture(&all.fixtures, "aot_backward_add");
    if let Some(reason) = &f.cascade_skip {
        if reason == SPEC_ONLY_SKIP {
            return;
        }
        eprintln!("cascade_skip(aot_backward_add): {reason}");
        return;
    }
    if let Some(reason) = cascade_skip("aot_backward_add") {
        eprintln!("cascade_skip: {reason}");
        return;
    }

    let input_shape = f.input_shape.as_ref().expect("input_shape");
    let expected_ga = f.expected_grad_a.as_ref().expect("expected_grad_a");
    let expected_gb = f.expected_grad_b.as_ref().expect("expected_grad_b");
    let tol = tol_f32(f);

    // Build forward graph: y = a + b
    let mut g = IrGraph::new();
    let a_id = g.add_input(input_shape.clone());
    let b_id = g.add_input(input_shape.clone());
    let (_, add_outs) = g.add_node(IrOpKind::Add, vec![a_id, b_id], vec![input_shape.clone()]);
    g.set_outputs(vec![add_outs[0]]);

    let pair = decompose_forward_backward(&g).unwrap();

    // The backward graph must have 2 output values (gradients for a and b).
    assert_eq!(
        pair.backward.output_values.len(),
        2,
        "aot_backward_add: expected 2 backward outputs"
    );

    // For Add: grad_a = grad_out and grad_b = grad_out.
    // Execute the backward graph with grad_out = [1,1,1].
    let grad_out_data = f.grad_out.as_ref().expect("grad_out");
    // Backward inputs: saved values + grad_output.
    // For Add (no multiply), saved_to_backward registers the forward inputs (a and b).
    // The backward graph's input_values are: [saved_0, saved_1, ..., grad_out].
    let n_bwd_inputs = pair.backward.input_values.len();
    let grad_out_t = shaped_f32(grad_out_data, input_shape);

    // Build the backward inputs: saved tensors (using the fixture input values) + grad_out.
    let a_data = f.input_a.as_ref().expect("input_a");
    let b_data = f.input_b.as_ref().expect("input_b");
    let a_t = shaped_f32(a_data, input_shape);
    let b_t = shaped_f32(b_data, input_shape);

    // The backward graph's first (n_bwd_inputs - 1) inputs are saved tensors;
    // the last is grad_output.
    let n_saved = n_bwd_inputs.saturating_sub(1);
    let saved_tensors = vec![a_t.clone(), b_t.clone()];
    let mut bwd_inputs: Vec<Tensor<f32>> = saved_tensors.into_iter().take(n_saved).collect();
    // Pad with zeros if we have fewer saved tensors than expected (conservative).
    while bwd_inputs.len() < n_saved {
        bwd_inputs.push(shaped_f32(
            &vec![0.0_f64; input_shape.iter().product()],
            input_shape,
        ));
    }
    bwd_inputs.push(grad_out_t);

    let bwd_results = interpret_multi::<f32>(&pair.backward, &bwd_inputs).unwrap();
    assert_eq!(
        bwd_results.len(),
        2,
        "aot_backward_add: expected 2 grad outputs"
    );

    assert_close(
        bwd_results[0].data().unwrap(),
        expected_ga,
        tol,
        "aot_backward_add: grad_a",
    );
    assert_close(
        bwd_results[1].data().unwrap(),
        expected_gb,
        tol,
        "aot_backward_add: grad_b",
    );
}

/// Fixture-driven: Mul backward — grad_a = b * grad_out, grad_b = a * grad_out.
