/// Fixture-driven: trace_with_breaks on all-supported ops produces Unbroken.
#[test]
fn graph_break_unbroken_add_sum_matches_reference() {
    let all = load_fixtures();
    let f = find_fixture(&all.fixtures, "graph_break_unbroken_add_sum");
    if let Some(reason) = &f.cascade_skip {
        if reason == SPEC_ONLY_SKIP {
            return;
        }
        eprintln!("cascade_skip(gb_unbroken): {reason}");
        return;
    }
    if let Some(reason) = cascade_skip("graph_break_unbroken_add_sum") {
        eprintln!("cascade_skip: {reason}");
        return;
    }

    let input_data = f.input.as_ref().expect("input");
    let input_shape = f
        .input_shape
        .as_ref()
        .cloned()
        .unwrap_or_else(|| vec![input_data.len()]);
    let expected = f.expected_output.as_ref().expect("expected_output");
    let tol = tol_f32(f);

    use ferrotorch_core::grad_fns::arithmetic::add;
    use ferrotorch_core::grad_fns::reduction::sum;

    let x_trace = grad_vec(input_data);
    let config = CompileConfig::default();

    let result = trace_with_breaks(
        |inputs: &[Tensor<f32>]| -> FerrotorchResult<Tensor<f32>> {
            let doubled = add(&inputs[0], &inputs[0])?;
            sum(&doubled)
        },
        &[x_trace],
        &config,
    )
    .unwrap();

    // Must produce TraceResult::Unbroken for all-supported ops.
    let graph = match result {
        TraceResult::Unbroken(g) => g,
        TraceResult::Segmented(_) => {
            panic!("graph_break_unbroken_add_sum: expected Unbroken, got Segmented");
        }
    };

    assert!(graph.node_count() >= 2, "graph must have at least 2 nodes");
    assert_eq!(graph.output_values.len(), 1);

    // Execute the unbroken graph with fresh inputs.
    let x_exec = shaped_f32(input_data, &input_shape);
    let exec_result = interpret::<f32>(&graph, &[x_exec]).unwrap();
    assert_eq!(exec_result.numel(), 1, "expected scalar sum output");
    let actual_val = exec_result.data().unwrap()[0];
    let expected_val = expected[0] as f32;
    assert!(
        (actual_val - expected_val).abs() < tol,
        "gb_unbroken: got {actual_val}, expected {expected_val} (tol {tol:.2e})"
    );
}

/// Fixture-driven: SegmentedModule forward — compiled + eager segments.
#[test]
fn graph_break_segmented_module_forward_matches_reference() {
    let all = load_fixtures();
    let f = find_fixture(&all.fixtures, "graph_break_segmented_module_forward");
    if let Some(reason) = &f.cascade_skip {
        if reason == SPEC_ONLY_SKIP {
            return;
        }
        eprintln!("cascade_skip(gb_segmented): {reason}");
        return;
    }
    if let Some(reason) = cascade_skip("graph_break_segmented_module_forward") {
        eprintln!("cascade_skip: {reason}");
        return;
    }

    let input_data = f.input.as_ref().expect("input");
    let expected = f.expected_output.as_ref().expect("expected_output");
    let tol = tol_f32(f);

    // Compiled segment: y = x + x
    let mut g = IrGraph::new();
    let x = g.add_input(vec![3]);
    let (_, add_outs) = g.add_node(IrOpKind::Add, vec![x, x], vec![vec![3]]);
    g.set_outputs(vec![add_outs[0]]);

    let compiled = TracedModule::<f32>::new(g);

    // Eager segment: multiply by 10.
    type EagerFn = Arc<dyn Fn(&Tensor<f32>) -> FerrotorchResult<Tensor<f32>> + Send + Sync>;
    let eager_fn: EagerFn = Arc::new(|input: &Tensor<f32>| {
        let n = input.numel();
        let ten = ferrotorch_core::from_vec(vec![10.0f32; n], input.shape()).unwrap();
        ferrotorch_core::grad_fns::arithmetic::mul(input, &ten)
    });

    let module = SegmentedModule::new(vec![
        GraphSegment::Compiled(compiled),
        GraphSegment::Eager(eager_fn),
    ]);

    assert_eq!(module.segment_count(), 2, "expected 2 segments");
    assert!(
        !module.is_fully_compiled(),
        "eager segment present → not fully compiled"
    );

    let input = shaped_f32(input_data, &[3]);
    let result = module.forward(&input).unwrap();

    assert_close(
        result.data().unwrap(),
        expected,
        tol,
        "gb_segmented_module_forward",
    );
}

